private void generateCombinations(List<Skin> skinList, List<Skin> currentTradeUpList, int index, int numIntervals, double averageSkinCost, double costThreshold, PriorityQueue<TradeUp> mostProfitableTradeups, int topN) {
    if (index == skinList.size()) {
